content.text:
Combined Input:
{
  "page": 1,
  "text": "Extracted text content...",
  "image": "Page 1 as image"
}
{
  "page": 2,
  "text": "Extracted text content...",
  "image": "Page 2 as image"
}
... (all pages)

# Method 1: URL
{"type": "file", "source": {"url": "https://example.com/document.pdf"}}

# Method 2: Base64 content
{"type": "file", "source": {
    "data": "base64_encoded_pdf_content",
    "media_type": "application/pdf"
}}

# Method 3: File reference
{"type": "file", "source": {"file_id": "file_abc123"}}  # Files API

# Files API (beta) - upload PDF once
file_response = claude.files.create(
    file="document.pdf",
    purpose="pdf_processing"
)
file_id = file_response.id  # "file_abc123"

# Reference in subsequent requests
messages=[{
    "role": "user",
    "content": [
        {"type": "file", "source": {"file_id": file_id}},
        {"type": "text", "text": "Summarize this document"}
    ]
}]
